import { Component, OnInit, signal } from '@angular/core';
import { ActivatedRoute, RouterLink } from '@angular/router';
import { CommonModule } from '@angular/common';
import { ProjectService } from '../../../core/services/project.service';
import { Project } from '../../../shared/models/project.model';

@Component({
  selector: 'app-project-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './project-detail.component.html'
})
export class ProjectDetailComponent implements OnInit {
  project = signal<Project | undefined>(undefined);
  notFound = signal(false);

  constructor(
    private route: ActivatedRoute,
    private projectService: ProjectService
  ) {}

  ngOnInit() {
    const id = this.route.snapshot.paramMap.get('id') ?? '';
    this.projectService.getProjectById(id).subscribe(project => {
      if (project) {
        this.project.set(project);
      } else {
        this.notFound.set(true);
      }
    });
  }
}
<div *ngIf="project() as p; else notFoundTpl" class="case-study">

  <a routerLink="/projects" class="back-link">← Back to Projects</a>

  <!-- Hero -->
  <header class="cs-hero">
    <h1>{{ p.title }}</h1>
    <p class="tagline">{{ p.tagline }}</p>
    <div class="tags">
      <span *ngFor="let tag of p.tags" class="tag">{{ tag }}</span>
    </div>
  </header>

  <!-- Case Study Sections -->
  <section class="cs-section">
    <h2>Overview</h2>
    <p>{{ p.overview }}</p>
  </section>

  <section class="cs-section">
    <h2>The Problem</h2>
    <p>{{ p.problem }}</p>
  </section>

  <section class="cs-section">
    <h2>The Solution</h2>
    <p>{{ p.solution }}</p>
  </section>

  <section class="cs-section">
    <h2>Outcome</h2>
    <p>{{ p.outcome }}</p>
  </section>

  <!-- Tech Stack -->
  <section class="cs-section">
    <h2>Tech Stack</h2>
    <ul class="tech-list">
      <li *ngFor="let tech of p.tech">{{ tech }}</li>
    </ul>
  </section>

  <!-- Screenshots -->
  <section class="cs-section" *ngIf="p.images?.length">
    <h2>Screenshots</h2>
    <div class="screenshot-grid">
      <img *ngFor="let img of p.images" [src]="img" [alt]="p.title + ' screenshot'" />
    </div>
  </section>

  <!-- Links -->
  <div class="cs-links">
    <a *ngIf="p.liveUrl" [href]="p.liveUrl" target="_blank" class="btn btn-primary">
      View Live ↗
    </a>
    <a *ngIf="p.repoUrl" [href]="p.repoUrl" target="_blank" class="btn btn-secondary">
      GitHub ↗
    </a>
  </div>
</div>

<!-- Not Found -->
<ng-template #notFoundTpl>
  <div class="not-found">
    <h2>Project not found</h2>
    <a routerLink="/projects">← Back to all projects</a>
  </div>
</ng-template>
